// Stage 2: 格式化简历文本，提取关键字段
// 输入: Extract from File 的纯文本输出
// 输出: 结构化的简历摘要对象

const items = $input.all();
const config = $('Config').first().json;

try {
  // 获取提取的文本
  let cvText = '';
  for (const item of items) {
    if (item.json.data) {
      cvText += item.json.data;
    } else if (item.json.text) {
      cvText += item.json.text;
    }
  }

  if (!cvText || cvText.trim().length < 50) {
    throw new Error('CV 文本提取失败或内容过短');
  }

  // 清理文本：移除多余空白和特殊字符
  cvText = cvText
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/\s{2,}/g, ' ')
    .trim();

  // 截断过长的简历（Claude 上下文限制）
  const MAX_CV_LENGTH = 8000;
  if (cvText.length > MAX_CV_LENGTH) {
    cvText = cvText.substring(0, MAX_CV_LENGTH) + '\n[... truncated for processing ...]';
  }

  return [{
    json: {
      cv_text: cvText,
      cv_length: cvText.length,
      extraction_timestamp: new Date().toISOString(),
      config: config
    }
  }];

} catch (error) {
  return [{
    json: {
      cv_text: '',
      cv_length: 0,
      error: error.message,
      extraction_timestamp: new Date().toISOString(),
      config: config
    }
  }];
}

// Stage 3: 标准化 LinkedIn 职位数据
// 输入: Apify scraper 返回的原始数据
// 输出: 统一格式的职位对象数组

const rawItems = $input.all();
const config = $('Config').first().json;

try {
  // Apify 可能以数组或单个对象返回
  let rawJobs = [];
  for (const item of rawItems) {
    if (Array.isArray(item.json)) {
      rawJobs = rawJobs.concat(item.json);
    } else if (item.json && item.json.title) {
      rawJobs.push(item.json);
    }
  }

  if (rawJobs.length === 0) {
    // 无职位时返回空标记
    return [{ json: { _no_jobs: true, config: config } }];
  }

  // 标准化每个职位的字段
  const normalizedJobs = rawJobs.map((job, index) => {
    // 提取 jobId（兼容不同 Apify 输出格式）
    const jobId = job.id || job.jobId || job.entityUrn?.split(':').pop() || `gen-${Date.now()}-${index}`;

    // 提取薪资信息（可能在不同字段中）
    const salary = job.salary || job.salaryInfo || job.companyApplyUrl || '';
    const salaryRange = typeof salary === 'object' 
      ? `${salary.min || ''} - ${salary.max || ''} ${salary.currency || 'AUD'}`
      : (salary || 'Not specified');

    return {
      job_id: String(jobId),
      title: (job.title || job.jobTitle || 'Unknown Title').trim(),
      company: (job.companyName || job.company || 'Unknown Company').trim(),
      location: (job.location || job.formattedLocation || 'Australia').trim(),
      posted_date: job.postedAt || job.listedAt || job.publishedAt || new Date().toISOString(),
      salary_range: salaryRange,
      linkedin_url: job.jobUrl || job.url || job.link || `https://www.linkedin.com/jobs/view/${jobId}`,
      description: (job.description || job.descriptionText || job.jobDescription || '').trim(),
      description_snippet: (job.description || job.descriptionText || '').substring(0, 300).trim(),
      seniority_level: job.seniorityLevel || job.experienceLevel || '',
      employment_type: job.employmentType || job.contractType || '',
      industry: job.industry || job.industries?.join(', ') || '',
      applicants_count: job.applicantsCount || job.numberOfApplicants || 0
    };
  });

  return normalizedJobs.map(job => ({ json: { ...job, config: config } }));

} catch (error) {
  return [{ json: { _error: error.message, _no_jobs: true, config: config } }];
}

// Stage 3: 关键词过滤 + jobId 去重
// 输入: 标准化后的职位数据
// 输出: 过滤和去重后的职位列表

const items = $input.all();
const config = $('Config').first().json;

try {
  // 检查是否无职位
  if (items.length === 1 && items[0].json._no_jobs) {
    return items;
  }

  // 解析排除关键词
  const excludeKeywords = (config.EXCLUDE_KEYWORDS || '')
    .split(',')
    .map(k => k.trim().toLowerCase())
    .filter(k => k.length > 0);

  // 去重 Map（基于 job_id）
  const seenIds = new Set();
  const filteredJobs = [];

  for (const item of items) {
    const job = item.json;

    // 跳过无效数据
    if (!job.job_id || !job.title) continue;

    // job_id 去重
    if (seenIds.has(job.job_id)) continue;
    seenIds.add(job.job_id);

    // 排除关键词过滤（检查标题和描述）
    const titleLower = (job.title || '').toLowerCase();
    const descLower = (job.description || '').toLowerCase();
    const shouldExclude = excludeKeywords.some(kw => 
      titleLower.includes(kw) || descLower.startsWith(kw)
    );

    if (shouldExclude) continue;

    // 检查描述是否为空（无法评分）
    if (!job.description || job.description.length < 50) continue;

    filteredJobs.push({ json: job });
  }

  if (filteredJobs.length === 0) {
    return [{ json: { _no_jobs: true, config: config } }];
  }

  return filteredJobs;

} catch (error) {
  return [{ json: { _error: error.message, _no_jobs: true, config: config } }];
}

// Stage 3.5: 检查是否有职位需要处理
// 如果无职位，分流到"无职位通知"分支

const items = $input.all();

if (items.length === 1 && items[0].json._no_jobs) {
  // 设置标记，后续 IF 节点会路由到空通知邮件
  return [{ json: { _no_jobs: true, config: items[0].json.config } }];
}

// 有职位，继续正常流程
return items;

// Stage 4: 合并 CV 文本 + Job Description，构造批次 prompt
// 输入: 过滤后的职位列表 + MapResume 的 CV 文本
// 输出: 按批次分组的 AI 输入

const jobs = $input.all();
const cvData = $('MapResume').first().json;
const config = $('Config').first().json;
const cvText = cvData.cv_text;
const batchSize = config.AI_BATCH_SIZE || 5;

if (!cvText || cvText.length < 50) {
  throw new Error('CV 文本无效，无法进行 AI 评分');
}

// 将职位按批次分组
const batches = [];
for (let i = 0; i < jobs.length; i += batchSize) {
  const batchJobs = jobs.slice(i, i + batchSize).map(item => ({
    job_id: item.json.job_id,
    title: item.json.title,
    company: item.json.company,
    location: item.json.location,
    description: item.json.description,
    seniority_level: item.json.seniority_level,
    employment_type: item.json.employment_type
  }));

  batches.push({
    json: {
      batch_index: Math.floor(i / batchSize),
      batch_size: batchJobs.length,
      total_jobs: jobs.length,
      cv_text: cvText,
      jobs: batchJobs,
      // 保留原始职位元数据（用于后续合并）
      jobs_meta: jobs.slice(i, i + batchSize).map(item => item.json)
    }
  });
}

return batches;

