// Stage 5-6: 解析 AI 输出 JSON，验证 Schema，合并元数据
// 输入: Claude API 响应 + 原始职位元数据
// 输出: 完整的评分+元数据对象

const items = $input.all();
const allResults = [];

// 权重定义（固定不可更改）
const WEIGHTS = {
  technical_skills_match: 0.35,
  experience_level_match: 0.25,
  language_requirements: 0.15,
  industry_domain_fit: 0.15,
  location_visa_compatibility: 0.10
};

// JSON Schema 验证函数
function validateScoreObject(obj) {
  const errors = [];

  if (!obj.job_id) errors.push('Missing job_id');
  if (!obj.scores) errors.push('Missing scores object');

  if (obj.scores) {
    for (const dim of Object.keys(WEIGHTS)) {
      if (!obj.scores[dim]) {
        errors.push(`Missing dimension: ${dim}`);
      } else {
        const s = obj.scores[dim].score;
        if (typeof s !== 'number' || s < 0 || s > 100) {
          errors.push(`Invalid score for ${dim}: ${s}`);
        }
      }
    }
  }

  if (!Array.isArray(obj.match_highlights)) errors.push('match_highlights must be array');
  if (!Array.isArray(obj.red_flags)) errors.push('red_flags must be array');

  const validActions = ['apply_now', 'worth_applying', 'low_priority'];
  if (!validActions.includes(obj.recommended_action)) {
    errors.push(`Invalid recommended_action: ${obj.recommended_action}`);
  }

  return errors;
}

// 显式计算加权总分
function calculateOverallScore(scores) {
  let total = 0;
  for (const [dim, weight] of Object.entries(WEIGHTS)) {
    const score = scores[dim]?.score || 0;
    total += score * weight;
  }
  return Math.round(total * 10) / 10; // 保留1位小数
}

for (const item of items) {
  try {
    const response = item.json;

    // 从 Claude 响应中提取文本内容
    let aiText = '';
    if (response.content && Array.isArray(response.content)) {
      aiText = response.content.map(c => c.text || '').join('');
    } else if (typeof response === 'string') {
      aiText = response;
    } else if (response.error) {
      console.log('AI API 错误:', response.error);
      continue;
    }

    // 清理 AI 输出（移除可能的 markdown 包裹）
    aiText = aiText.trim();
    if (aiText.startsWith('```json')) {
      aiText = aiText.replace(/^```json\s*/, '').replace(/\s*```$/, '');
    } else if (aiText.startsWith('```')) {
      aiText = aiText.replace(/^```\s*/, '').replace(/\s*```$/, '');
    }

    // 解析 JSON
    let scoreData;
    try {
      scoreData = JSON.parse(aiText);
    } catch (parseErr) {
      // 尝试修复常见 JSON 错误
      aiText = aiText.replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
      try {
        scoreData = JSON.parse(aiText);
      } catch (e) {
        console.log('JSON 解析失败，跳过此批次:', parseErr.message);
        continue;
      }
    }

    // 确保是数组格式
    const scoreArray = Array.isArray(scoreData) ? scoreData : [scoreData];

    // 获取对应批次的元数据
    const batchMeta = $('Prepare AI Input').all();

    for (const score of scoreArray) {
      // 验证 Schema
      const validationErrors = validateScoreObject(score);
      if (validationErrors.length > 0) {
        console.log(`职位 ${score.job_id} 验证失败:`, validationErrors.join('; '));
        // 尝试修复而非跳过
        if (!score.scores) continue;
      }

      // 强制使用固定权重重新计算 overall_score
      for (const dim of Object.keys(WEIGHTS)) {
        if (score.scores[dim]) {
          score.scores[dim].weight = WEIGHTS[dim];
        }
      }
      const calculatedScore = calculateOverallScore(score.scores);
      score.overall_score = calculatedScore;

      // 查找对应的元数据
      let jobMeta = null;
      for (const batch of batchMeta) {
        if (batch.json.jobs_meta) {
          const found = batch.json.jobs_meta.find(m => String(m.job_id) === String(score.job_id));
          if (found) {
            jobMeta = found;
            break;
          }
        }
      }

      // 合并评分与元数据
      allResults.push({
        json: {
          job_id: score.job_id,
          title: jobMeta?.title || 'Unknown',
          company: jobMeta?.company || 'Unknown',
          location: jobMeta?.location || 'Australia',
          posted_date: jobMeta?.posted_date || new Date().toISOString(),
          salary_range: jobMeta?.salary_range || 'Not specified',
          linkedin_url: jobMeta?.linkedin_url || '#',
          description_snippet: jobMeta?.description_snippet || '',
          overall_score: score.overall_score,
          recommended_action: score.recommended_action || 'low_priority',
          scores: score.scores,
          match_highlights: (score.match_highlights || []).slice(0, 3),
          red_flags: score.red_flags || []
        }
      });
    }

  } catch (error) {
    console.log('处理批次时出错:', error.message);
    continue; // 跳过当前批次，继续处理其他
  }
}

if (allResults.length === 0) {
  return [{ json: { _no_scored_jobs: true } }];
}

return allResults;

// Stage 7: 按 overall_score 降序排列，取 Top N
// 输入: 合并后的评分+元数据对象
// 输出: 排序后的 Top N 职位

const items = $input.all();
const config = $('Config').first().json;
const topN = config.TOP_N_JOBS || 15;
const minScore = config.MIN_OVERALL_SCORE || 0;

// 过滤无效项和低分项
const validJobs = items
  .filter(item => !item.json._no_scored_jobs && item.json.overall_score !== undefined)
  .filter(item => item.json.overall_score >= minScore);

if (validJobs.length === 0) {
  return [{ json: { _no_jobs: true, config: config } }];
}

// 降序排列
validJobs.sort((a, b) => b.json.overall_score - a.json.overall_score);

// 取前 N 个
const topJobs = validJobs.slice(0, topN);

return topJobs;

// Stage 8: 生成精美 HTML 邮件报告
// 输入: 排序后的 Top N 职位
// 输出: { subject: string, html: string }

const items = $input.all();
const config = $('Config').first().json;
const runDate = config.RUN_DATE || new Date().toISOString().split('T')[0];

// 检查是否无职位
if (items.length === 1 && (items[0].json._no_jobs || items[0].json._no_scored_jobs)) {
  const emptyHtml = `
  <html><body style="font-family:Arial,sans-serif;background:#f5f5f5;padding:20px;">
    <table width="600" cellpadding="0" cellspacing="0" align="center" style="background:#fff;border-radius:8px;overflow:hidden;">
      <tr><td style="background:#1a1a2e;color:#fff;padding:30px;text-align:center;">
        <h1 style="margin:0;font-size:24px;">📋 Daily Job Report</h1>
        <p style="margin:5px 0 0;opacity:0.8;">${runDate}</p>
      </td></tr>
      <tr><td style="padding:40px;text-align:center;">
        <p style="font-size:18px;color:#666;">No new matching jobs found today.</p>
        <p style="color:#999;">The agent will search again tomorrow at 07:30 AEST.</p>
      </td></tr>
    </table>
  </body></html>`;

  return [{ json: { 
    subject: `📋 Daily Job Report | ${runDate} | No new matches`, 
    html: emptyHtml 
  }}];
}

const jobs = items.map(i => i.json);
const totalJobs = jobs.length;

// 颜色工具函数
function getScoreColor(score) {
  if (score >= 90) return '#22c55e';  // 绿色
  if (score >= 70) return '#f59e0b';  // 黄色
  return '#ef4444';                    // 红色
}

function getActionBadge(action) {
  switch(action) {
    case 'apply_now': return '<span style="display:inline-block;background:#22c55e;color:#fff;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">🚀 APPLY NOW</span>';
    case 'worth_applying': return '<span style="display:inline-block;background:#3b82f6;color:#fff;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">👍 WORTH APPLYING</span>';
    default: return '<span style="display:inline-block;background:#9ca3af;color:#fff;padding:4px 12px;border-radius:12px;font-size:12px;font-weight:bold;">⏸️ LOW PRIORITY</span>';
  }
}

// 生成 emoji 进度条
function emojiBar(score) {
  const filled = Math.round(score / 10);
  const empty = 10 - filled;
  const color = score >= 80 ? '🟢' : score >= 60 ? '🟡' : '🔴';
  return color.repeat(filled) + '⚪'.repeat(empty) + ` ${score}`;
}

// 构建职位卡片 HTML
function buildJobCard(job, rank) {
  const scoreColor = getScoreColor(job.overall_score);
  const progressWidth = Math.min(job.overall_score, 100);

  const highlightsHtml = (job.match_highlights || []).map(h => 
    `<tr><td style="padding:2px 0;font-size:13px;color:#059669;">✅ ${h}</td></tr>`
  ).join('');

  const redFlagsHtml = (job.red_flags || []).length > 0 
    ? job.red_flags.map(f => 
        `<tr><td style="padding:2px 0;font-size:13px;color:#dc2626;">⚠️ ${f}</td></tr>`
      ).join('')
    : '';

  const scores = job.scores || {};

  return `
    <tr><td style="padding:8px 20px;">
      <table width="100%" cellpadding="0" cellspacing="0" style="background:#fff;border:1px solid #e5e7eb;border-radius:8px;overflow:hidden;margin-bottom:4px;">
        <!-- 卡片头部 -->
        <tr><td style="padding:16px 20px;border-bottom:1px solid #f3f4f6;">
          <table width="100%" cellpadding="0" cellspacing="0">
            <tr>
              <td style="vertical-align:top;">
                <span style="font-size:12px;color:#9ca3af;">#${rank}</span>
                <h3 style="margin:2px 0 4px;font-size:16px;color:#1f2937;">${job.title}</h3>
                <p style="margin:0;font-size:14px;color:#6b7280;font-weight:600;">${job.company}</p>
                <p style="margin:4px 0 0;font-size:12px;color:#9ca3af;">📍 ${job.location} · 🕐 ${job.posted_date?.split('T')[0] || 'Recent'}</p>
                <p style="margin:2px 0 0;font-size:12px;color:#9ca3af;">💰 ${job.salary_range}</p>
              </td>
              <td width="120" style="text-align:center;vertical-align:top;">
                <div style="font-size:32px;font-weight:bold;color:${scoreColor};">${job.overall_score}</div>
                <div style="font-size:11px;color:#9ca3af;">MATCH SCORE</div>
                <div style="margin-top:6px;">${getActionBadge(job.recommended_action)}</div>
              </td>
            </tr>
          </table>
        </td></tr>

        <!-- 分数进度条 -->
        <tr><td style="padding:12px 20px;">
          <table width="100%" cellpadding="0" cellspacing="0" style="background:#f3f4f6;border-radius:4px;overflow:hidden;">
            <tr><td>
              <div style="height:8px;width:${progressWidth}%;background:${scoreColor};border-radius:4px;"></div>
            </td></tr>
          </table>
        </td></tr>

        <!-- 五维度评分 -->
        <tr><td style="padding:4px 20px 12px;">
          <table width="100%" cellpadding="2" cellspacing="0" style="font-size:12px;color:#4b5563;">
            <tr><td width="200">🔧 Technical Skills</td><td>${emojiBar(scores.technical_skills_match?.score || 0)}</td></tr>
            <tr><td>📊 Experience Level</td><td>${emojiBar(scores.experience_level_match?.score || 0)}</td></tr>
            <tr><td>🗣️ Language</td><td>${emojiBar(scores.language_requirements?.score || 0)}</td></tr>
            <tr><td>🏢 Industry Fit</td><td>${emojiBar(scores.industry_domain_fit?.score || 0)}</td></tr>
            <tr><td>📍 Location/Visa</td><td>${emojiBar(scores.location_visa_compatibility?.score || 0)}</td></tr>
          </table>
        </td></tr>

        <!-- 亮点和红旗 -->
        <tr><td style="padding:4px 20px 12px;">
          <table width="100%" cellpadding="0" cellspacing="0">
            ${highlightsHtml}
            ${redFlagsHtml}
          </table>
        </td></tr>

        <!-- 查看按钮 -->
        <tr><td style="padding:8px 20px 16px;text-align:center;">
          <a href="${job.linkedin_url}" target="_blank" style="display:inline-block;background:#0077b5;color:#fff;padding:10px 28px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:bold;">🔗 View on LinkedIn</a>
        </td></tr>
      </table>
    </td></tr>`;
}

// 汇总统计
const applyNowCount = jobs.filter(j => j.recommended_action === 'apply_now').length;
const avgScore = (jobs.reduce((s, j) => s + j.overall_score, 0) / jobs.length).toFixed(1);

// 主 HTML 模板
const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <meta name="color-scheme" content="light dark">
